const item = $input.first().json; 
const headers = item.headers || {}; 
const body = item.body || item; 

// 1. PRODUCTION SECURITY ROTATION: Enforce your new unexposed secret token key
const expectedKey = "git-policy-n8n-secure-rag-52601"; 
const authHeader = headers.authorization || headers.Authorization || ""; 

if (authHeader !== "Bearer " + expectedKey) { 
  return [{ 
    json: { 
      error: true, 
      statusCode: 403, 
      response: { 
        error_code: 1002, 
        error_msg: "Authorization failed: Invalid token rotation key." 
      } 
    } 
  }]; 
} 

const knowledgeId = body.knowledge_id || ""; 
const query = body.query; 
const retrieval = body.retrieval_setting || {}; 

// 2. Namespace Tracking Verification
if (knowledgeId !== "gitlab-us-time-off" && knowledgeId !== "gitlab-us-time-off-chunked") { 
  return [{ 
    json: { 
      error: true, 
      statusCode: 404, 
      response: { 
        error_code: 2001, 
        error_msg: "Knowledge base not found" 
      } 
    } 
  }]; 
} 

if (!query) { 
  return [{ 
    json: { 
      error: true, 
      statusCode: 400, 
      response: { 
        error_code: 1003, 
        error_msg: "Missing query parameter payload" 
      } 
    } 
  }]; 
} 

// 3. Return your synchronized parameters to downstream REST client nodes
return [{ 
  json: { 
    query, 
    knowledge_id: knowledgeId, 
    top_k: retrieval.top_k || 8, 
    score_threshold: 0.0, 
    namespace: "gitlab-us-time-off-chunked" 
  } 
}];

const embeddingResponse = $input.first().json; 
const values = embeddingResponse.embedding?.values || embeddingResponse.embeddings?.[0]?.values || []; 

if (!values.length) { 
  throw new Error("No query embedding returned from Gemini API"); 
}

return [{ 
  json: { 
    vector: values, 
    top_k: 8, 
    score_threshold: 0.0, 
    namespace: "gitlab-us-time-off-chunked" 
  } 
}];

const pinecone = $input.first().json; 
const settings = $("Build Pinecone Query - Code").first().json; 
const threshold = 0.0; // Open gate to pass everything to Dify safely
const matches = pinecone.matches || pinecone.results || []; 

const records = matches 
  .map(match => { 
    const metadata = match.metadata || (match.document && match.document.metadata) || {}; 
    const extractedContent = match.pageContent || (match.document && match.document.pageContent) || metadata.pageContent || metadata.text || "";

    // Sanitize your tracking strings
    const cleanFilePath = (metadata.file_path || "").trim();
    const cleanSourceUrl = (metadata.source_url || "").trim();
    const cleanCommitSha = (metadata.commit_sha || "").trim();

    return { 
      content: extractedContent, 
      score: match.score || 0, 
      title: metadata.title || metadata.heading_path || cleanFilePath || "GitLab policy chunk", 
      metadata: { 
        // 1. DIFY MANDATORY CAMELCASE KEYS (The Secret Fix)
        filePath: cleanFilePath,
        sourceUrl: cleanSourceUrl,
        commitSha: cleanCommitSha,

        // 2. LEGACY SNAKE_CASE KEYS (For fallback compatibility)
        chunk_id: metadata.chunk_id || match.id || "", 
        document_id: metadata.document_id || "", 
        file_path: cleanFilePath, 
        source_url: cleanSourceUrl, 
        heading_path: metadata.heading_path || "", 
        commit_sha: cleanCommitSha, 
        blob_sha: metadata.blob_sha || "", 
        chunk_index: metadata.chunk_index ?? null, 
        chunk_word_count: metadata.chunk_word_count ?? null, 
        split_reason: metadata.split_reason || "" 
      } 
    }; 
  }) 
  .filter(record => record.content.trim().length > 0); 

return [{ json: { records } }];
